145	export function KtpCatalogPage() {
146	  const { subjectId = "" } = useParams<{ subjectId: string }>();
147	  const role = useAppSelector(state => state.adminAuth.role);
148	
149	  const { data: catalog, isLoading } = useGetKtpCatalogQuery(subjectId, { skip: !subjectId });
150	  const [addTopic] = useAddKtpTopicMutation();
151	  const [updateTopic] = useUpdateKtpTopicMutation();
152	  const [deleteTopic] = useDeleteKtpTopicMutation();
153	  const [reorderTopics] = useReorderKtpTopicsMutation();
154	  const [upsertMeta] = useUpsertKtpMetaMutation();
155	  const [importTopics] = useImportKtpTopicsMutation();
156	
157	  const [newTitle, setNewTitle] = useState("");
158	  const [yearInput, setYearInput] = useState("");
159	  const [versionInput, setVersionInput] = useState("");
160	  const [importText, setImportText] = useState("");
161	  const [importReplace, setImportReplace] = useState(true);
162	  const [error, setError] = useState<string | null>(null);
163	
164	  const topics = useMemo(
165	    () => (catalog ? [...catalog.topics].sort((a, b) => a.order - b.order) : []),
166	    [catalog],
167	  );
168	
169	  if (role !== "admin") {
170	    return (
171	      <Box sx={{ p: 4 }}>
172	        <Alert severity="warning">Справочник КТП может редактировать только администратор.</Alert>
173	      </Box>
174	    );
175	  }
176	
177	  const run = async (fn: () => Promise<unknown>) => {
178	    setError(null);
179	    try {
180	      await fn();
181	    } catch {
182	      setError("Не удалось выполнить операцию. Попробуйте ещё раз.");
183	    }
184	  };
185	
186	  const handleAdd = () => {
187	    const title = newTitle.trim();
188	    if (!title) return;
189	    void run(async () => {
190	      await addTopic({ subjectId, body: { title } }).unwrap();
191	      setNewTitle("");
192	    });
193	  };
194	
195	  const handleSaveMeta = () => {
196	    const year = yearInput.trim() ? Number(yearInput.trim()) : undefined;
197	    const version = versionInput.trim() ? Number(versionInput.trim()) : undefined;
198	    void run(() => upsertMeta({ subjectId, year, version }).unwrap());
199	  };
200	
201	  const move = (index: number, dir: -1 | 1) => {
202	    const target = index + dir;
203	    if (target < 0 || target >= topics.length) return;
204	    const reordered = [...topics];
205	    const a = reordered[index];
206	    const b = reordered[target];
207	    if (!a || !b) return;
208	    reordered[index] = b;
209	    reordered[target] = a;
210	    void run(() => reorderTopics({ subjectId, orderedTopicIds: reordered.map(t => t._id) }).unwrap());
211	  };
212	
213	  const handleImport = () => {
214	    if (!importText.trim()) return;
215	    let parsed: unknown;
216	    try {
217	      parsed = JSON.parse(importText);
218	    } catch {
219	      setError("Невалидный JSON");
220	      return;
221	    }
222	    const raw = Array.isArray(parsed) ? parsed : (parsed as { topics?: unknown }).topics;
223	    if (!Array.isArray(raw)) {
224	      setError('Ожидается массив тем или объект { "topics": [...] }');
225	      return;
226	    }
227	    void run(async () => {
228	      await importTopics({ subjectId, topics: raw as KtpTopicInput[], replace: importReplace }).unwrap();
229	      setImportText("");
230	    });
231	  };
232	
233	  return (
234	    <Box sx={{ p: { xs: 2, md: 4 }, maxWidth: 900, mx: "auto" }}>
235	      <Typography variant="h5" fontWeight={700} gutterBottom>
236	        Справочник КТП
237	      </Typography>
238	      <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
239	        Канонический упорядоченный список тем предмета. Роудмап строится из КТП: темы книг (разных
240	        классов) мапятся на эти темы.
241	      </Typography>
242	
243	      {error && (
244	        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
245	          {error}
246	        </Alert>
247	      )}
248	
249	      <Paper variant="outlined" sx={{ p: 2, mb: 3 }}>
250	        <Stack direction="row" spacing={2} alignItems="flex-end" flexWrap="wrap">
251	          <TextField
252	            label="Год"
253	            size="small"
254	            value={yearInput}
255	            onChange={e => setYearInput(e.target.value)}
256	            placeholder={catalog?.year ? String(catalog.year) : "2026"}
257	            sx={{ width: 120 }}
258	          />
259	          <TextField
260	            label="Версия"
261	            size="small"
262	            value={versionInput}
263	            onChange={e => setVersionInput(e.target.value)}
264	            placeholder={catalog ? String(catalog.version) : "1"}
265	            sx={{ width: 120 }}
266	          />
267	          <Button variant="outlined" onClick={handleSaveMeta}>
268	            Сохранить
269	          </Button>
270	        </Stack>
271	      </Paper>
272	
273	      <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
274	        Темы КТП ({topics.length})
275	      </Typography>
276	
277	      {isLoading && <Typography variant="body2">Загрузка…</Typography>}
278	      {!isLoading && topics.length === 0 && (
279	        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
280	          Тем пока нет. Добавьте вручную или импортируйте JSON ниже.
281	        </Typography>
282	      )}
283	
284	      <Stack spacing={1} sx={{ mb: 2 }}>
285	        {topics.map((topic, index) => (
286	          <KtpTopicRow
287	            key={topic._id}
288	            topic={topic}
289	            index={index}
290	            total={topics.length}
291	            onMove={move}
292	            onSave={body => void run(() => updateTopic({ subjectId, topicId: topic._id, body }).unwrap())}
293	            onDelete={() => void run(() => deleteTopic({ subjectId, topicId: topic._id }).unwrap())}
294	          />
295	        ))}
296	      </Stack>
297	
298	      <Stack direction="row" spacing={1} sx={{ mb: 4 }}>
299	        <TextField
300	          size="small"
301	          fullWidth
302	          label="Новая тема КТП"
303	          value={newTitle}
304	          onChange={e => setNewTitle(e.target.value)}
305	          onKeyDown={e => {
306	            if (e.key === "Enter") handleAdd();
307	          }}
308	        />
309	        <Button variant="contained" onClick={handleAdd}>
310	          Добавить
311	        </Button>
312	      </Stack>
313	
314	      <Divider sx={{ mb: 3 }} />
315	
316	      <Typography variant="subtitle1" fontWeight={600} sx={{ mb: 1 }}>
317	        Массовый импорт (JSON)
318	      </Typography>
319	      <Typography variant="caption" color="text.secondary" component="p" sx={{ mb: 1 }}>
320	        Формат: массив объектов {"{ title, code?, description?, order? }"} или {'{ "topics": [...] }'}.
321	      </Typography>
322	      <TextField
323	        multiline
324	        minRows={4}
325	        fullWidth
326	        value={importText}
327	        onChange={e => setImportText(e.target.value)}
328	        placeholder='[{ "title": "Клетка", "code": "1.1" }, { "title": "Митохондрии" }]'
329	        sx={{ mb: 1 }}
330	      />
331	      <Stack direction="row" spacing={2} alignItems="center">
332	        <FormControlLabel
333	          control={<Checkbox checked={importReplace} onChange={e => setImportReplace(e.target.checked)} />}
334	          label="Заменить существующие"
335	        />
336	        <Button variant="outlined" onClick={handleImport}>
337	          Импортировать
338	        </Button>
339	      </Stack>
340	    </Box>
341	  );
342	}
