=== KTP TYPES ===
/** Тема КТП. _id — стабильный id для маппинга тем книг и nodeId роудмапа. */
export interface KtpTopic {
  _id: string;
  title: string;
  description?: string;
  order: number;
  /** Код темы от центра тестирования (отображение/импорт) */
  code?: string;
}

/** Справочник КТП по предмету (канонический упорядоченный список тем). */
export interface KtpCatalog {
  _id: string;
  subjectId: string;
  year?: number;
  version: number;
  topics: KtpTopic[];
}

/** Тело создания/изменения темы КТП. */
export interface KtpTopicInput {
  title: string;
  description?: string;
  order?: number;
  code?: string;
}

