72	}: {
73	  onConfirm: () => Promise<void> | void;
74	  tooltip?: string;
75	  title?: string;
76	  body?: React.ReactNode;
77	  confirmLabel?: string;
78	  icon?: React.ReactNode;
79	}) {
80	  const [open, setOpen] = useState(false);
81	  const [loading, setLoading] = useState(false);
82	  const [error, setError] = useState<string | null>(null);
83	
84	  const close = () => {
85	    setOpen(false);
86	    setError(null);
87	  };
