124	        body={body}
125	        confirmLabel={confirmLabel}
126	        confirmColor="error"
127	        loading={loading}
128	        error={error}
129	        onConfirm={handleConfirm}
130	        onClose={close}
131	      />
132	    </>
133	  );
134	}
