3	export type Flash = (message: string, severity?: "success" | "error") => void;
4	
5	interface UnwrappableTrigger {
6	  unwrap: () => Promise<unknown>;
7	}
8	
9	/**
10	 * Выполняет RTK-мутацию через .unwrap() и показывает тост успеха или ошибки.
11	 * Возвращает true при успехе — чтобы вызывающий мог не сбрасывать ввод при ошибке.
12	 * Без .unwrap() триггер RTK не реджектится, поэтому раньше ошибки молча терялись
13	 * и показывался ложный «успех».
14	 */
15	export async function runMutation(
16	  flash: Flash,
17	  trigger: UnwrappableTrigger,
18	  okMessage: string,
19	): Promise<boolean> {
20	  try {
21	    await trigger.unwrap();
22	    flash(okMessage);
23	    return true;
24	  } catch (e) {
25	    flash(apiErrorMessage(e), "error");
26	    return false;
27	  }
28	}
